def valid_sudoku_3x3(grid):
    if len(grid) != 3 or any(len(row) != 3 for row in grid):
        return False
    seen = set()
    for row in grid:
        for num in row:
            if num < 1 or num > 9 or num in seen:
                return False
            seen.add(num)
    return True
